def normalize_text(s: str) -> str:
    s = s.strip().lower()
    s = re.sub(r\s+", " ", s)
    s = re.sub(r"[^a-z0-9\s\-]", "", s)
    return s

def build_document(record: dict) -> dict:
    return {
        "id": record.get("id"),
        "title": normalize_text(record.get("title", "")),
        "body": normalize_text(record.get("body", "")),
        "tags": record.get("tags", [])
    }"}

