{"artifact_type":"text/code","label":"worker-job","uri":"ipfs://bafybeijobrunner","storage_path":"s3://artifacts-prod/code/job_runner.js","encoding":"utf-8","content":"const { Client } = require('pg');

async function runJob({ jobId }) {
  const client = new Client({ connectionString: process.env.DATABASE_URL });
  await client.connect();
  try {
    await client.query('UPDATE jobs SET status=$1, started_at=NOW() WHERE id=$2', ['running', jobId]);
    // Simulate work
    await new Promise(r => setTimeout(r, 500));
    await client.query('UPDATE jobs SET status=$1, finished_at=NOW() WHERE id=$2', ['done', jobId]);
  } finally {
    await client.end();
  }
}

module.exports = { runJob };"}

